const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

module.exports = async function (context, req) {
    const sendGridApiKey = process.env.SENDGRID_API_KEY || 'SG.azure_demo_key_123';
    const twilioSid = process.env.TWILIO_SID || 'AC1234567890abcdef';
    const twilioAuthToken = process.env.TWILIO_AUTH_TOKEN || 'your_twilio_auth_token';
    const twilioPhoneNumber = process.env.TWILIO_PHONE_NUMBER || 'your_twilio_phone_number';

    sgMail.setApiKey(sendGridApiKey);

    try {
        // Send email using SendGrid
        const emailResponse = await sgMail.send({
            to: req.body.emailTo,
            from: 'your_email@example.com',
            subject: 'Azure Function Email',
            text: 'This is a test email from Azure Function using SendGrid.'
        });

        // Send SMS using Twilio
        const client = twilio(twilioSid, twilioAuthToken);
        const smsResponse = await client.messages.create({
            body: 'This is a test SMS from Azure Function using Twilio.',
            from: twilioPhoneNumber,
            to: req.body.smsTo
        });

        context.res = {
            status: 200,
            body: {
                emailResponse: emailResponse,
                smsResponse: smsResponse
            }
        };
    } catch (error) {
        context.res = {
            status: 500,
            body: { error: error.message }
        };
    }
};